import socket
import requests
from urllib.parse import urlparse

ALLOWED_DOMAINS = {'example.com', 'another-allowed-domain.com'}

def is_ip_allowed(ip):
    # Check if the IP is in private, loopback, or other restricted ranges
    restricted_ranges = [
        ('127.0.0.0', '127.255.255.255'),  # Loopback
        ('10.0.0.0', '10.255.255.255'),    # Private
        ('172.16.0.0', '172.31.255.255'),  # Private
        ('192.168.0.0', '192.168.255.255'),# Private
        ('169.254.0.0', '169.254.255.255'),# Link-local
        ('224.0.0.0', '239.255.255.255'),  # Multicast
    ]
    ip_addr = int.from_bytes(socket.inet_aton(ip), 'big')
    for start, end in restricted_ranges:
        if int.from_bytes(socket.inet_aton(start), 'big') <= ip_addr <= int.from_bytes(socket.inet_aton(end), 'big'):
            return False
    return True

def fetch_url_content(url):
    parsed_url = urlparse(url)
    if parsed_url.hostname not in ALLOWED_DOMAINS:
        raise ValueError("Domain not allowed")
    
    try:
        ip = socket.gethostbyname(parsed_url.hostname)
        if not is_ip_allowed(ip):
            raise ValueError("IP address not allowed")
    except socket.error:
        raise ValueError("Invalid hostname")

    try:
        response = requests.get(url, allow_redirects=False)
        if response.is_redirect:
            redirect_url = response.headers.get('Location')
            if redirect_url:
                return fetch_url_content(redirect_url)
        return response.text
    except requests.RequestException as e:
        raise ValueError(f"Request failed: {e}")

